// BAD: silently truncates if x > type(uint32).max
// uint32 small = uint32(x);

// GOOD: OpenZeppelin SafeCast reverts on overflow
import {SafeCast} from "@openzeppelin/contracts/utils/math/SafeCast.sol";

using SafeCast for uint256;

function store(uint256 x) external {
    uint32 small = x.toUint32(); // reverts if x does not fit in 32 bits
    packedValue = small;
}

// Alternative without a library: check the bound explicitly first
require(x <= type(uint32).max, "value exceeds uint32");
uint32 checked = uint32(x);
